### 10.1 CandlestickChart.razor (YENİ)
**Dosya:** `src/CryptoTrader/Traxon.CryptoTrader.Dashboard/Components/Charts/CandlestickChart.razor`

LightweightCharts.Blazor kullanır.

Önemli: Developer, LightweightCharts.Blazor'un güncel API'sini NuGet belgelerinden kontrol etmeli.
Temel entegrasyon:
1. `<Chart>` component render et
2. `OnAfterRenderAsync(firstRender)`: `AddCandlestickSeriesAsync()` çağır
3. InitialData: `ILiveFeedService` veya `IDbContextFactory<AppDbContext>`'ten son 200 candle yükle
4. `Feed.OnCandleUpdate` subscribe → `UpdateAsync()` çağır

```razor
@using LightweightCharts.Blazor.Charts
@using LightweightCharts.Blazor.Models
@using LightweightCharts.Blazor.Series
@inject ILiveFeedService Feed
@inject IDbContextFactory<Traxon.CryptoTrader.Infrastructure.Persistence.AppDbContext> DbFactory
@implements IDisposable

<div style="width:100%; height:@(Height)px; background-color: var(--color-bg-surface); border-radius: var(--radius-card); overflow: hidden;">
    <Chart @ref="_chart"
           Layout="@_layout"
           style="width:100%; height:100%;" />
</div>

@code {
    [Parameter, EditorRequired] public string Symbol { get; set; } = "BTCUSDT";
    [Parameter, EditorRequired] public string Interval { get; set; } = "5m";
    [Parameter] public int Height { get; set; } = 400;

    private Chart? _chart;
    private ICandlestickSeries? _series;

    private readonly LayoutOptions _layout = new()
    {
        Background = new SolidColor { Color = "#111111" },
        TextColor = "#888888"
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender || _chart is null) return;

        _series = await _chart.AddCandlestickSeriesAsync();

        // Initial data from DB
        await using var db = await DbFactory.CreateDbContextAsync();
        var candles = await db.Candles
            .Where(c => c.Symbol == Symbol && c.Interval == Interval)
            .OrderBy(c => c.OpenTime)
            .TakeLast(200)
            .ToListAsync();

        var data = candles.Select(c => new CandlestickData
        {
            Time = new DateTimeOffset(c.OpenTime, TimeSpan.Zero).ToUnixTimeSeconds(),
            Open = (float)c.Open,
            High = (float)c.High,
            Low = (float)c.Low,
            Close = (float)c.Close
        }).ToArray();

        if (data.Length > 0)
            await _series.SetDataAsync(data);

        Feed.OnCandleUpdate += OnCandle;
    }

    private void OnCandle(CandleDto candle)
    {
        if (candle.Symbol != Symbol || candle.Interval != Interval) return;
        // Fire-and-forget: update chart on Blazor thread
        InvokeAsync(async () =>
        {
            if (_series is null) return;
            await _series.UpdateAsync(new CandlestickData
            {
                Time = new DateTimeOffset(candle.OpenTime, TimeSpan.Zero).ToUnixTimeSeconds(),
                Open = (float)candle.Open,
                High = (float)candle.High,
                Low = (float)candle.Low,
                Close = (float)candle.Close
            });
        });
    }

    public void Dispose() => Feed.OnCandleUpdate -= OnCandle;
}
```

