    private readonly ApexChartOptions<EquityPoint> _options = new()
    {
        Chart = new ApexCharts.Chart { Background = "#111111", ForeColor = "#888888" },
        Theme = new Theme { Mode = Mode.Dark }
    };

    protected override async Task OnInitializedAsync()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var snapshots = await db.PortfolioSnapshots
            .OrderBy(p => p.Timestamp)
            .TakeLast(500)
            .ToListAsync();

        _series = snapshots
            .GroupBy(p => p.Engine)
            .ToDictionary(
                g => g.Key,
                g => g.Select(p => new EquityPoint(new DateTimeOffset(p.Timestamp, TimeSpan.Zero), p.Balance)).ToList());
    }

    private record EquityPoint(DateTimeOffset Timestamp, decimal Balance);
}
